sql:
SELECT MAX(cgpa) 
FROM students 
WHERE discipline_id = 1;

SELECT discipline_id, COUNT(offer_id) AS num_job_offers
FROM job_offers
GROUP BY discipline_id;

SELECT placement_percentage
FROM placement_statistics
WHERE discipline_id = 1;

SELECT discipline_name
FROM disciplines
WHERE discipline_id = 0;

SELECT department_head 
FROM disciplines 
ORDER BY discipline_name ASC;
